INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-math-1','exam','exam:math','exam-math-1','beginner','mcq','If 3x = 18, what is the value of x?','If 3x = 18, what is the value of x?',ARRAY['3','6','9','15']::text[],ARRAY['3','6','9','15']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Dividing both sides of 3x = 18 by 3 gives x = 6.','Dividing both sides of 3x = 18 by 3 gives x = 6.','To solve a one-step linear equation, isolate the variable by performing the inverse operation on both sides. Here the variable is multiplied by 3, so you divide both sides by 3. Keeping both sides balanced is the core rule of equation solving.','To solve a one-step linear equation, isolate the variable by performing the inverse operation on both sides. Here the variable is multiplied by 3, so you divide both sides by 3. Keeping both sides balanced is the core rule of equation solving.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-math-2','exam','exam:math','exam-math-2','intermediate','mcq','A shirt originally priced at $40 is discounted by 25%. What is the sale price?','A shirt originally priced at $40 is discounted by 25%. What is the sale price?',ARRAY['$10','$15','$30','$35']::text[],ARRAY['$10','$15','$30','$35']::text[],2,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A 25% discount removes 0.25 x $40 = $10, leaving $40 - $10 = $30.','A 25% discount removes 0.25 x $40 = $10, leaving $40 - $10 = $30.','A percent discount is a fraction of the original amount that is subtracted. You can find the result either by computing the discount and subtracting, or by multiplying the original by (1 minus the discount rate). For a 25% discount that means multiplying by 0.75.','A percent discount is a fraction of the original amount that is subtracted. You can find the result either by computing the discount and subtracting, or by multiplying the original by (1 minus the discount rate). For a 25% discount that means multiplying by 0.75.',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-math-3','exam','exam:math','exam-math-3','advanced','mcq','If f(x) = 2x^2 - 3x + 1, what is the value of f(3)?','If f(x) = 2x^2 - 3x + 1, what is the value of f(3)?',ARRAY['8','10','13','19']::text[],ARRAY['8','10','13','19']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Substituting x = 3 gives 2(9) - 3(3) + 1 = 18 - 9 + 1 = 10.','Substituting x = 3 gives 2(9) - 3(3) + 1 = 18 - 9 + 1 = 10.','Evaluating a function means substituting the given input for the variable everywhere it appears, then simplifying using order of operations. Exponents are computed before multiplication, and multiplication before addition or subtraction. Careful sign handling on each term prevents common errors.','Evaluating a function means substituting the given input for the variable everywhere it appears, then simplifying using order of operations. Exponents are computed before multiplication, and multiplication before addition or subtraction. Careful sign handling on each term prevents common errors.',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-reading-1','exam','exam:reading','exam-reading-1','beginner','mcq','In the sentence "The hikers were elated when they finally reached the summit," the word "elated" most nearly means:','In the sentence "The hikers were elated when they finally reached the summit," the word "elated" most nearly means:',ARRAY['exhausted','overjoyed','confused','frightened']::text[],ARRAY['exhausted','overjoyed','confused','frightened']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Reaching a long-sought summit is a triumphant moment, so "elated" means overjoyed.','Reaching a long-sought summit is a triumphant moment, so "elated" means overjoyed.','Vocabulary-in-context questions ask you to infer a word''s meaning from the surrounding clues rather than a dictionary definition alone. Look at the tone and situation of the sentence to narrow choices. Here the positive event of reaching the top signals a positive emotion.','Vocabulary-in-context questions ask you to infer a word''s meaning from the surrounding clues rather than a dictionary definition alone. Look at the tone and situation of the sentence to narrow choices. Here the positive event of reaching the top signals a positive emotion.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-reading-2','exam','exam:reading','exam-reading-2','intermediate','mcq','Read this sentence: "Although the new policy was intended to reduce traffic, it inadvertently encouraged more drivers to use side streets." What is the main idea of this sentence?','Read this sentence: "Although the new policy was intended to reduce traffic, it inadvertently encouraged more drivers to use side streets." What is the main idea of this sentence?',ARRAY['The policy worked exactly as planned.','The policy had an unintended effect opposite to its goal.','Side streets are safer than main roads.','Drivers ignored the new policy entirely.']::text[],ARRAY['The policy worked exactly as planned.','The policy had an unintended effect opposite to its goal.','Side streets are safer than main roads.','Drivers ignored the new policy entirely.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The word "inadvertently" signals an unintended result that worked against the policy''s goal of reducing traffic.','The word "inadvertently" signals an unintended result that worked against the policy''s goal of reducing traffic.','The main idea of a sentence is its central point once supporting details are stripped away. Contrast words like "although" and "inadvertently" flag a gap between intention and outcome. Identifying these signal words helps you pin down what the writer is really emphasizing.','The main idea of a sentence is its central point once supporting details are stripped away. Contrast words like "although" and "inadvertently" flag a gap between intention and outcome. Identifying these signal words helps you pin down what the writer is really emphasizing.',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-reading-3','exam','exam:reading','exam-reading-3','advanced','mcq','In the sentence "Her arguments, though superficially compelling, ultimately proved specious upon closer scrutiny," the word "specious" most nearly means:','In the sentence "Her arguments, though superficially compelling, ultimately proved specious upon closer scrutiny," the word "specious" most nearly means:',ARRAY['genuinely persuasive','deliberately offensive','seemingly true but actually false','overly complicated']::text[],ARRAY['genuinely persuasive','deliberately offensive','seemingly true but actually false','overly complicated']::text[],2,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The contrast between "superficially compelling" and the result of closer scrutiny shows that "specious" means appearing true but actually false.','The contrast between "superficially compelling" and the result of closer scrutiny shows that "specious" means appearing true but actually false.','Advanced vocabulary-in-context items reward attention to contrast and qualification. The phrase "superficially compelling" sets up an appearance, while "upon closer scrutiny" undercuts it. "Specious" specifically describes reasoning that looks valid on the surface but collapses under examination.','Advanced vocabulary-in-context items reward attention to contrast and qualification. The phrase "superficially compelling" sets up an appearance, while "upon closer scrutiny" undercuts it. "Specious" specifically describes reasoning that looks valid on the surface but collapses under examination.',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-grammar-1','exam','exam:grammar','exam-grammar-1','beginner','mcq','Which sentence is grammatically correct?','Which sentence is grammatically correct?',ARRAY['The dog wag its tail happily.','The dog wags its tail happily.','The dog wagging its tail happily.','The dog wag it''s tail happily.']::text[],ARRAY['The dog wag its tail happily.','The dog wags its tail happily.','The dog wagging its tail happily.','The dog wag it''s tail happily.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A singular subject ("dog") takes the singular present-tense verb "wags," and "its" is the correct possessive.','A singular subject ("dog") takes the singular present-tense verb "wags," and "its" is the correct possessive.','Subject-verb agreement requires a singular subject to pair with a singular verb, which in the present tense usually ends in -s. The possessive "its" has no apostrophe, while "it''s" is a contraction of "it is." Distinguishing these two is a frequent test point.','Subject-verb agreement requires a singular subject to pair with a singular verb, which in the present tense usually ends in -s. The possessive "its" has no apostrophe, while "it''s" is a contraction of "it is." Distinguishing these two is a frequent test point.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-grammar-2','exam','exam:grammar','exam-grammar-2','intermediate','mcq','Choose the option that correctly completes the sentence: "Neither the manager nor the employees ___ aware of the schedule change."','Choose the option that correctly completes the sentence: "Neither the manager nor the employees ___ aware of the schedule change."',ARRAY['was','were','is','be']::text[],ARRAY['was','were','is','be']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'With "neither...nor," the verb agrees with the nearer subject, "employees," which is plural and takes "were."','With "neither...nor," the verb agrees with the nearer subject, "employees," which is plural and takes "were."','When subjects are joined by "neither...nor" or "either...or," the verb agrees with the subject closest to it. Because "employees" is plural and sits nearest the verb, the plural "were" is correct. Reordering the subjects can change the required verb form.','When subjects are joined by "neither...nor" or "either...or," the verb agrees with the subject closest to it. Because "employees" is plural and sits nearest the verb, the plural "were" is correct. Reordering the subjects can change the required verb form.',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-grammar-3','exam','exam:grammar','exam-grammar-3','advanced','mcq','Which sentence corrects the dangling modifier in "Walking to the office, the rain soaked my coat"?','Which sentence corrects the dangling modifier in "Walking to the office, the rain soaked my coat"?',ARRAY['Walking to the office, my coat was soaked by the rain.','The rain soaked my coat, walking to the office.','Walking to the office, I got my coat soaked by the rain.','Walking to the office the rain soaked my coat completely.']::text[],ARRAY['Walking to the office, my coat was soaked by the rain.','The rain soaked my coat, walking to the office.','Walking to the office, I got my coat soaked by the rain.','Walking to the office the rain soaked my coat completely.']::text[],2,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The modifier "walking to the office" must describe a person, so the subject should be "I," the one doing the walking.','The modifier "walking to the office" must describe a person, so the subject should be "I," the one doing the walking.','A dangling modifier is an introductory phrase whose implied subject does not match the actual subject of the main clause. Rain cannot walk, so the sentence must place a person who can walk right after the modifier. Fixing it means making the doer of the action the grammatical subject.','A dangling modifier is an introductory phrase whose implied subject does not match the actual subject of the main clause. Rain cannot walk, so the sentence must place a person who can walk right after the modifier. Fixing it means making the doer of the action the grammatical subject.',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-reasoning-1','exam','exam:reasoning','exam-reasoning-1','beginner','mcq','All birds have feathers. A robin is a bird. Which conclusion must be true?','All birds have feathers. A robin is a bird. Which conclusion must be true?',ARRAY['A robin has feathers.','All feathered animals are robins.','Only robins have feathers.','A robin cannot fly.']::text[],ARRAY['A robin has feathers.','All feathered animals are robins.','Only robins have feathers.','A robin cannot fly.']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Since all birds have feathers and a robin is a bird, it follows necessarily that a robin has feathers.','Since all birds have feathers and a robin is a bird, it follows necessarily that a robin has feathers.','A valid deductive syllogism applies a general rule to a specific case to reach a guaranteed conclusion. The conclusion must follow strictly from the premises without adding outside information. Reversing the rule (assuming all feathered animals are birds) is a common logical error.','A valid deductive syllogism applies a general rule to a specific case to reach a guaranteed conclusion. The conclusion must follow strictly from the premises without adding outside information. Reversing the rule (assuming all feathered animals are birds) is a common logical error.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-reasoning-2','exam','exam:reasoning','exam-reasoning-2','intermediate','mcq','A study found that towns with more ice cream sales also have more swimming-pool accidents. Which statement best explains why ice cream sales do not necessarily cause the accidents?','A study found that towns with more ice cream sales also have more swimming-pool accidents. Which statement best explains why ice cream sales do not necessarily cause the accidents?',ARRAY['Ice cream makes swimmers careless.','Hot weather independently increases both ice cream sales and swimming.','Swimming-pool accidents reduce ice cream sales.','The study used too small a sample.']::text[],ARRAY['Ice cream makes swimmers careless.','Hot weather independently increases both ice cream sales and swimming.','Swimming-pool accidents reduce ice cream sales.','The study used too small a sample.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A third factor, hot weather, raises both ice cream sales and swimming activity, so the two are correlated without one causing the other.','A third factor, hot weather, raises both ice cream sales and swimming activity, so the two are correlated without one causing the other.','Correlation does not imply causation, because two variables can move together due to a shared underlying cause. This hidden third variable is called a confounder. Identifying a plausible confounder is the standard way to weaken a claimed causal link.','Correlation does not imply causation, because two variables can move together due to a shared underlying cause. This hidden third variable is called a confounder. Identifying a plausible confounder is the standard way to weaken a claimed causal link.',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-exam-reasoning-3','exam','exam:reasoning','exam-reasoning-3','advanced','mcq','An ad claims: "Nine out of ten dentists surveyed recommend our toothpaste." Which question most effectively challenges this claim?','An ad claims: "Nine out of ten dentists surveyed recommend our toothpaste." Which question most effectively challenges this claim?',ARRAY['How much does the toothpaste cost?','How many dentists were surveyed, and how were they selected?','Do dentists use toothpaste themselves?','Is the toothpaste available in stores?']::text[],ARRAY['How much does the toothpaste cost?','How many dentists were surveyed, and how were they selected?','Do dentists use toothpaste themselves?','Is the toothpaste available in stores?']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The claim''s strength depends on sample size and selection, so asking how many dentists were surveyed and how they were chosen exposes possible bias.','The claim''s strength depends on sample size and selection, so asking how many dentists were surveyed and how they were chosen exposes possible bias.','Statistical claims can mislead when the sample is small, unrepresentative, or selected to favor a result. Asking about sample size and selection method tests whether the data can be generalized. This scrutiny of methodology is central to evaluating evidence in critical reasoning.','Statistical claims can mislead when the sample is small, unrepresentative, or selected to favor a result. Asking about sample size and selection method tests whether the data can be generalized. This scrutiny of methodology is central to evaluating evidence in critical reasoning.',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-math-b-1','exam','exam:math','exam-math-b-1','beginner','mcq','If 3x + 5 = 20, what is the value of x?','If 3x + 5 = 20, what is the value of x?',ARRAY['3','5','7','15']::text[],ARRAY['3','5','7','15']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Subtracting 5 from both sides gives 3x = 15, and dividing both sides by 3 gives x = 5.','Subtracting 5 from both sides gives 3x = 15, and dividing both sides by 3 gives x = 5.','To solve a linear equation, isolate the variable by performing inverse operations on both sides. First undo addition or subtraction, then undo multiplication or division. Always do the same operation to both sides to keep the equation balanced.','To solve a linear equation, isolate the variable by performing inverse operations on both sides. First undo addition or subtraction, then undo multiplication or division. Always do the same operation to both sides to keep the equation balanced.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-math-b-2','exam','exam:math','exam-math-b-2','beginner','mcq','What is 20% of 150?','What is 20% of 150?',ARRAY['20','30','45','75']::text[],ARRAY['20','30','45','75']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'20% equals 0.20, and 0.20 multiplied by 150 equals 30.','20% equals 0.20, and 0.20 multiplied by 150 equals 30.','A percent means ''per hundred,'' so to find a percent of a number you convert the percent to a decimal by dividing by 100, then multiply. For example, 20% becomes 0.20. Multiplying the decimal by the whole gives the part.','A percent means ''per hundred,'' so to find a percent of a number you convert the percent to a decimal by dividing by 100, then multiply. For example, 20% becomes 0.20. Multiplying the decimal by the whole gives the part.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-math-i-1','exam','exam:math','exam-math-i-1','intermediate','mcq','A shirt originally priced at $40 is discounted by 25%. What is the sale price?','A shirt originally priced at $40 is discounted by 25%. What is the sale price?',ARRAY['$10','$25','$30','$35']::text[],ARRAY['$10','$25','$30','$35']::text[],2,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A 25% discount removes 0.25 times 40, which is $10, leaving 40 minus 10 equals $30.','A 25% discount removes 0.25 times 40, which is $10, leaving 40 minus 10 equals $30.','To apply a percentage discount, calculate the discount amount by multiplying the original price by the percent as a decimal, then subtract it from the original. Alternatively, multiply the original price by (1 minus the discount rate). Both methods give the final sale price.','To apply a percentage discount, calculate the discount amount by multiplying the original price by the percent as a decimal, then subtract it from the original. Alternatively, multiply the original price by (1 minus the discount rate). Both methods give the final sale price.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-math-i-2','exam','exam:math','exam-math-i-2','intermediate','mcq','If the average (arithmetic mean) of 4, 8, and x is 10, what is the value of x?','If the average (arithmetic mean) of 4, 8, and x is 10, what is the value of x?',ARRAY['10','12','16','18']::text[],ARRAY['10','12','16','18']::text[],3,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The mean of 10 over 3 numbers means their sum is 30, and 30 minus 4 minus 8 equals 18.','The mean of 10 over 3 numbers means their sum is 30, and 30 minus 4 minus 8 equals 18.','The arithmetic mean equals the sum of the values divided by how many values there are. To find a missing value, multiply the mean by the count to get the total sum, then subtract the known values. This reverses the averaging process.','The arithmetic mean equals the sum of the values divided by how many values there are. To find a missing value, multiply the mean by the count to get the total sum, then subtract the known values. This reverses the averaging process.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-math-a-1','exam','exam:math','exam-math-a-1','advanced','mcq','If x^2 - 5x + 6 = 0, what are all the solutions for x?','If x^2 - 5x + 6 = 0, what are all the solutions for x?',ARRAY['x = 1 and x = 6','x = 2 and x = 3','x = -2 and x = -3','x = 5 and x = 6']::text[],ARRAY['x = 1 and x = 6','x = 2 and x = 3','x = -2 and x = -3','x = 5 and x = 6']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The quadratic factors as (x - 2)(x - 3) = 0, giving roots x = 2 and x = 3 since each factor can equal zero.','The quadratic factors as (x - 2)(x - 3) = 0, giving roots x = 2 and x = 3 since each factor can equal zero.','A quadratic equation can often be solved by factoring it into two binomials whose product is zero. Find two numbers that multiply to the constant term and add to the coefficient of the middle term. By the zero-product property, setting each factor to zero gives the solutions.','A quadratic equation can often be solved by factoring it into two binomials whose product is zero. Find two numbers that multiply to the constant term and add to the coefficient of the middle term. By the zero-product property, setting each factor to zero gives the solutions.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-math-a-2','exam','exam:math','exam-math-a-2','advanced','mcq','A jar holds 5 red and 3 blue marbles. If two marbles are drawn without replacement, what is the probability that both are red?','A jar holds 5 red and 3 blue marbles. If two marbles are drawn without replacement, what is the probability that both are red?',ARRAY['5/14','25/64','5/8','1/2']::text[],ARRAY['5/14','25/64','5/8','1/2']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The first red has probability 5/8 and the second 4/7, and (5/8) times (4/7) equals 20/56, which simplifies to 5/14.','The first red has probability 5/8 and the second 4/7, and (5/8) times (4/7) equals 20/56, which simplifies to 5/14.','For dependent events without replacement, multiply the probability of the first event by the probability of the second given the first occurred. Each draw changes both the favorable count and the total count. Simplify the resulting fraction to lowest terms.','For dependent events without replacement, multiply the probability of the first event by the probability of the second given the first occurred. Each draw changes both the favorable count and the total count. Simplify the resulting fraction to lowest terms.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reading-b-1','exam','exam:reading','exam-reading-b-1','beginner','mcq','Read this sentence: ''The marathon runner felt utterly depleted as she crossed the finish line.'' In this context, ''depleted'' most nearly means:','Read this sentence: ''The marathon runner felt utterly depleted as she crossed the finish line.'' In this context, ''depleted'' most nearly means:',ARRAY['energized','exhausted','joyful','confused']::text[],ARRAY['energized','exhausted','joyful','confused']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'After running a marathon a runner would feel drained of energy, so ''depleted'' means exhausted.','After running a marathon a runner would feel drained of energy, so ''depleted'' means exhausted.','Vocabulary-in-context questions ask for a word''s meaning based on the surrounding sentence, not just its dictionary definition. Use clues such as the situation described and nearby descriptive words to infer the intended sense. Substitute each option into the sentence to test which fits the tone and logic.','Vocabulary-in-context questions ask for a word''s meaning based on the surrounding sentence, not just its dictionary definition. Use clues such as the situation described and nearby descriptive words to infer the intended sense. Substitute each option into the sentence to test which fits the tone and logic.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reading-b-2','exam','exam:reading','exam-reading-b-2','beginner','mcq','Read this passage: ''Honeybees communicate the location of food through a movement called the waggle dance. The angle and duration of the dance tell other bees the direction and distance to the flowers.'' What is the main idea?','Read this passage: ''Honeybees communicate the location of food through a movement called the waggle dance. The angle and duration of the dance tell other bees the direction and distance to the flowers.'' What is the main idea?',ARRAY['Honeybees prefer certain flowers','The waggle dance conveys food location information','Bees cannot see colors','Dancing tires the bees out']::text[],ARRAY['Honeybees prefer certain flowers','The waggle dance conveys food location information','Bees cannot see colors','Dancing tires the bees out']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Both sentences focus on how the waggle dance communicates the direction and distance to food, making that the main idea.','Both sentences focus on how the waggle dance communicates the direction and distance to food, making that the main idea.','The main idea is the central point a passage is built around, supported by its details. Look for the topic that every sentence relates to rather than a single specific fact. Distractors often state true but minor details or claims the passage never makes.','The main idea is the central point a passage is built around, supported by its details. Look for the topic that every sentence relates to rather than a single specific fact. Distractors often state true but minor details or claims the passage never makes.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reading-i-1','exam','exam:reading','exam-reading-i-1','intermediate','mcq','Read this passage: ''Although the new policy was praised by economists, ordinary citizens found their daily costs rising with little visible benefit.'' What can be inferred about the citizens'' view of the policy?','Read this passage: ''Although the new policy was praised by economists, ordinary citizens found their daily costs rising with little visible benefit.'' What can be inferred about the citizens'' view of the policy?',ARRAY['They strongly supported it','They were skeptical or dissatisfied with it','They did not notice the policy','They were economists themselves']::text[],ARRAY['They strongly supported it','They were skeptical or dissatisfied with it','They did not notice the policy','They were economists themselves']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Rising costs with little visible benefit implies citizens were dissatisfied, contrasting with the economists'' praise.','Rising costs with little visible benefit implies citizens were dissatisfied, contrasting with the economists'' praise.','An inference is a conclusion drawn from evidence in the text that is not stated outright. Words like ''although'' signal a contrast that helps reveal an implied attitude. Choose the option best supported by the passage without going beyond what the clues justify.','An inference is a conclusion drawn from evidence in the text that is not stated outright. Words like ''although'' signal a contrast that helps reveal an implied attitude. Choose the option best supported by the passage without going beyond what the clues justify.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reading-i-2','exam','exam:reading','exam-reading-i-2','intermediate','mcq','Read this sentence: ''The critic''s review was scathing, dismissing the film as a hollow spectacle.'' What is the author''s tone toward the film, as reported by the critic?','Read this sentence: ''The critic''s review was scathing, dismissing the film as a hollow spectacle.'' What is the author''s tone toward the film, as reported by the critic?',ARRAY['Admiring','Neutral','Harshly critical','Nostalgic']::text[],ARRAY['Admiring','Neutral','Harshly critical','Nostalgic']::text[],2,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Words like ''scathing'' and ''dismissing'' and the phrase ''hollow spectacle'' convey a harshly critical tone.','Words like ''scathing'' and ''dismissing'' and the phrase ''hollow spectacle'' convey a harshly critical tone.','Tone is the author''s or speaker''s attitude toward the subject, revealed through word choice. Strongly charged words such as ''scathing'' or ''hollow'' signal negative judgment. Identify the emotional weight of key words to determine whether the tone is positive, negative, or neutral.','Tone is the author''s or speaker''s attitude toward the subject, revealed through word choice. Strongly charged words such as ''scathing'' or ''hollow'' signal negative judgment. Identify the emotional weight of key words to determine whether the tone is positive, negative, or neutral.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reading-a-1','exam','exam:reading','exam-reading-a-1','advanced','mcq','Read this passage: ''Proponents claim the bridge will ease congestion. Yet by making driving more convenient, such projects often attract more drivers, eventually restoring the very gridlock they sought to relieve.'' The second sentence primarily serves to:','Read this passage: ''Proponents claim the bridge will ease congestion. Yet by making driving more convenient, such projects often attract more drivers, eventually restoring the very gridlock they sought to relieve.'' The second sentence primarily serves to:',ARRAY['Restate the proponents'' claim','Provide a counterargument to the proponents'' claim','Give an example of a successful bridge','Define the word congestion']::text[],ARRAY['Restate the proponents'' claim','Provide a counterargument to the proponents'' claim','Give an example of a successful bridge','Define the word congestion']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The word ''Yet'' introduces a rebuttal arguing the bridge may not ease congestion, so it functions as a counterargument.','The word ''Yet'' introduces a rebuttal arguing the bridge may not ease congestion, so it functions as a counterargument.','Function questions ask what role a sentence plays in the structure of an argument, not just what it says. Transition words like ''yet,'' ''however,'' or ''therefore'' reveal whether a sentence supports, qualifies, or opposes a prior claim. Identify the relationship between sentences to name the rhetorical purpose.','Function questions ask what role a sentence plays in the structure of an argument, not just what it says. Transition words like ''yet,'' ''however,'' or ''therefore'' reveal whether a sentence supports, qualifies, or opposes a prior claim. Identify the relationship between sentences to name the rhetorical purpose.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reading-a-2','exam','exam:reading','exam-reading-a-2','advanced','mcq','Read this passage: ''The author argues that solitude, far from being mere loneliness, is a fertile ground for creativity, citing writers who produced their best work in isolation.'' Which assumption underlies the author''s argument?','Read this passage: ''The author argues that solitude, far from being mere loneliness, is a fertile ground for creativity, citing writers who produced their best work in isolation.'' Which assumption underlies the author''s argument?',ARRAY['All creative people are lonely','Isolation can foster, rather than hinder, creative production','Writers dislike company','Loneliness and solitude are identical']::text[],ARRAY['All creative people are lonely','Isolation can foster, rather than hinder, creative production','Writers dislike company','Loneliness and solitude are identical']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'By presenting solitude as ''fertile ground'' supported by isolated writers, the author assumes isolation can foster creativity rather than hinder it.','By presenting solitude as ''fertile ground'' supported by isolated writers, the author assumes isolation can foster creativity rather than hinder it.','An underlying assumption is an unstated premise that must be true for an argument to hold. To find it, identify the gap between the evidence given and the conclusion drawn. The correct assumption bridges that gap without overstating or contradicting the passage.','An underlying assumption is an unstated premise that must be true for an argument to hold. To find it, identify the gap between the evidence given and the conclusion drawn. The correct assumption bridges that gap without overstating or contradicting the passage.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-grammar-b-1','exam','exam:grammar','exam-grammar-b-1','beginner','mcq','Choose the option that correctly completes the sentence: ''The team of scientists ___ presenting its findings tomorrow.''','Choose the option that correctly completes the sentence: ''The team of scientists ___ presenting its findings tomorrow.''',ARRAY['are','is','were','be']::text[],ARRAY['are','is','were','be']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The subject ''team'' is a singular collective noun acting as one unit, so it takes the singular verb ''is.''','The subject ''team'' is a singular collective noun acting as one unit, so it takes the singular verb ''is.''','Subject-verb agreement requires a verb to match its subject in number, ignoring intervening prepositional phrases like ''of scientists.'' Collective nouns such as ''team'' are usually treated as singular when the group acts as a unit. Identify the true subject before choosing the verb form.','Subject-verb agreement requires a verb to match its subject in number, ignoring intervening prepositional phrases like ''of scientists.'' Collective nouns such as ''team'' are usually treated as singular when the group acts as a unit. Identify the true subject before choosing the verb form.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-grammar-b-2','exam','exam:grammar','exam-grammar-b-2','beginner','mcq','Which sentence uses the apostrophe correctly to show possession?','Which sentence uses the apostrophe correctly to show possession?',ARRAY['The dogs bone was buried.','The dog''s bone was buried.','The dogs'' bone was buried by one dog.','The dogs bone''s was buried.']::text[],ARRAY['The dogs bone was buried.','The dog''s bone was buried.','The dogs'' bone was buried by one dog.','The dogs bone''s was buried.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A single dog owning the bone takes an apostrophe plus s, giving ''dog''s bone.''','A single dog owning the bone takes an apostrophe plus s, giving ''dog''s bone.''','A possessive apostrophe shows ownership. For a singular noun, add apostrophe plus s; for a plural noun already ending in s, add only an apostrophe after the s. Apostrophes are not used to make ordinary nouns plural.','A possessive apostrophe shows ownership. For a singular noun, add apostrophe plus s; for a plural noun already ending in s, add only an apostrophe after the s. Apostrophes are not used to make ordinary nouns plural.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-grammar-i-1','exam','exam:grammar','exam-grammar-i-1','intermediate','mcq','Which sentence corrects the dangling modifier in ''Walking into the room, the lights were already on.''?','Which sentence corrects the dangling modifier in ''Walking into the room, the lights were already on.''?',ARRAY['Walking into the room, the lights were already on.','The lights were already on, walking into the room.','Walking into the room, I saw that the lights were already on.','Walking into the room the lights, were already on.']::text[],ARRAY['Walking into the room, the lights were already on.','The lights were already on, walking into the room.','Walking into the room, I saw that the lights were already on.','Walking into the room the lights, were already on.']::text[],2,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The modifier ''walking into the room'' needs a person to perform the action, so adding ''I saw'' gives it a logical subject.','The modifier ''walking into the room'' needs a person to perform the action, so adding ''I saw'' gives it a logical subject.','A dangling modifier is an introductory phrase that does not logically attach to the subject that follows it. To fix it, rewrite the sentence so the word the phrase describes appears right after the modifier. Lights cannot walk, so the sentence needs a person as the subject.','A dangling modifier is an introductory phrase that does not logically attach to the subject that follows it. To fix it, rewrite the sentence so the word the phrase describes appears right after the modifier. Lights cannot walk, so the sentence needs a person as the subject.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-grammar-i-2','exam','exam:grammar','exam-grammar-i-2','intermediate','mcq','Choose the correctly punctuated sentence.','Choose the correctly punctuated sentence.',ARRAY['I finished my work, I went home.','I finished my work; I went home.','I finished my work I went home.','I finished my work, so; I went home.']::text[],ARRAY['I finished my work, I went home.','I finished my work; I went home.','I finished my work I went home.','I finished my work, so; I went home.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Two independent clauses can be joined by a semicolon, so ''I finished my work; I went home.'' is correct.','Two independent clauses can be joined by a semicolon, so ''I finished my work; I went home.'' is correct.','A comma alone cannot join two independent clauses, which is the error called a comma splice. A semicolon correctly links two closely related independent clauses without a conjunction. Alternatively, a comma plus a coordinating conjunction, or a period, would also be correct.','A comma alone cannot join two independent clauses, which is the error called a comma splice. A semicolon correctly links two closely related independent clauses without a conjunction. Alternatively, a comma plus a coordinating conjunction, or a period, would also be correct.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-grammar-a-1','exam','exam:grammar','exam-grammar-a-1','advanced','mcq','Which sentence maintains correct parallel structure?','Which sentence maintains correct parallel structure?',ARRAY['She likes hiking, swimming, and to bike.','She likes hiking, swimming, and biking.','She likes to hike, swimming, and biking.','She likes hike, swim, and biking.']::text[],ARRAY['She likes hiking, swimming, and to bike.','She likes hiking, swimming, and biking.','She likes to hike, swimming, and biking.','She likes hike, swim, and biking.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'All three items use the same ''-ing'' gerund form, making ''hiking, swimming, and biking'' parallel.','All three items use the same ''-ing'' gerund form, making ''hiking, swimming, and biking'' parallel.','Parallel structure requires that items in a list or series share the same grammatical form. Mixing gerunds with infinitives, as in ''hiking'' and ''to bike,'' breaks parallelism. Ensure every element in a coordinated series matches in form.','Parallel structure requires that items in a list or series share the same grammatical form. Mixing gerunds with infinitives, as in ''hiking'' and ''to bike,'' breaks parallelism. Ensure every element in a coordinated series matches in form.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-grammar-a-2','exam','exam:grammar','exam-grammar-a-2','advanced','mcq','Which sentence correctly uses the subjunctive mood?','Which sentence correctly uses the subjunctive mood?',ARRAY['If I was rich, I would travel.','If I were rich, I would travel.','If I am rich, I would travel.','If I be rich, I would travel.']::text[],ARRAY['If I was rich, I would travel.','If I were rich, I would travel.','If I am rich, I would travel.','If I be rich, I would travel.']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Contrary-to-fact conditions use the subjunctive ''were,'' giving ''If I were rich, I would travel.''','Contrary-to-fact conditions use the subjunctive ''were,'' giving ''If I were rich, I would travel.''','The subjunctive mood expresses hypothetical, wishful, or contrary-to-fact situations. In such ''if'' clauses, use ''were'' for all subjects instead of ''was.'' The main clause typically pairs it with ''would'' plus a base verb.','The subjunctive mood expresses hypothetical, wishful, or contrary-to-fact situations. In such ''if'' clauses, use ''were'' for all subjects instead of ''was.'' The main clause typically pairs it with ''would'' plus a base verb.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reasoning-b-1','exam','exam:reasoning','exam-reasoning-b-1','beginner','mcq','All cats are mammals. Whiskers is a cat. Which conclusion logically follows?','All cats are mammals. Whiskers is a cat. Which conclusion logically follows?',ARRAY['Whiskers is a mammal','All mammals are cats','Whiskers is a dog','Some mammals are not cats']::text[],ARRAY['Whiskers is a mammal','All mammals are cats','Whiskers is a dog','Some mammals are not cats']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'If all cats are mammals and Whiskers is a cat, then Whiskers must be a mammal.','If all cats are mammals and Whiskers is a cat, then Whiskers must be a mammal.','A valid syllogism draws a conclusion that must be true if its premises are true. When every member of a category has a property and an individual belongs to that category, the individual has the property. Be careful not to reverse the relationship, which is a common logical error.','A valid syllogism draws a conclusion that must be true if its premises are true. When every member of a category has a property and an individual belongs to that category, the individual has the property. Be careful not to reverse the relationship, which is a common logical error.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reasoning-b-2','exam','exam:reasoning','exam-reasoning-b-2','beginner','truefalse','Consider the statement: ''If it rains, the ground gets wet. The ground is wet.'' It logically follows with certainty that it rained.','Consider the statement: ''If it rains, the ground gets wet. The ground is wet.'' It logically follows with certainty that it rained.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The ground could be wet from another cause such as a sprinkler, so it does not follow with certainty that it rained.','The ground could be wet from another cause such as a sprinkler, so it does not follow with certainty that it rained.','Affirming the consequent is a logical fallacy where one assumes a cause from an observed effect. ''If A then B'' does not mean ''if B then A,'' because B may have other causes. A wet ground is consistent with rain but does not prove it.','Affirming the consequent is a logical fallacy where one assumes a cause from an observed effect. ''If A then B'' does not mean ''if B then A,'' because B may have other causes. A wet ground is consistent with rain but does not prove it.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reasoning-i-1','exam','exam:reasoning','exam-reasoning-i-1','intermediate','mcq','A study found that towns with more ice cream sales also had more drownings. Which statement best explains this without claiming ice cream causes drownings?','A study found that towns with more ice cream sales also had more drownings. Which statement best explains this without claiming ice cream causes drownings?',ARRAY['Ice cream makes people swim poorly','Hot weather increases both ice cream sales and swimming','Drowning increases appetite for ice cream','The study must be wrong']::text[],ARRAY['Ice cream makes people swim poorly','Hot weather increases both ice cream sales and swimming','Drowning increases appetite for ice cream','The study must be wrong']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Hot weather is a common cause that raises both ice cream sales and swimming, explaining the correlation without direct causation.','Hot weather is a common cause that raises both ice cream sales and swimming, explaining the correlation without direct causation.','Correlation does not imply causation; two variables can rise together because of a third factor. A confounding variable, such as hot weather here, influences both observed variables. Identifying a plausible common cause explains the link without asserting one variable causes the other.','Correlation does not imply causation; two variables can rise together because of a third factor. A confounding variable, such as hot weather here, influences both observed variables. Identifying a plausible common cause explains the link without asserting one variable causes the other.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reasoning-i-2','exam','exam:reasoning','exam-reasoning-i-2','intermediate','mcq','An ad claims: ''Nine out of ten dentists surveyed recommend our toothpaste.'' Which question most weakens this claim?','An ad claims: ''Nine out of ten dentists surveyed recommend our toothpaste.'' Which question most weakens this claim?',ARRAY['What flavor is the toothpaste?','How many dentists were surveyed and how were they chosen?','Do dentists like toothpaste?','Is the toothpaste sold in stores?']::text[],ARRAY['What flavor is the toothpaste?','How many dentists were surveyed and how were they chosen?','Do dentists like toothpaste?','Is the toothpaste sold in stores?']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'If very few dentists were surveyed or they were selected in a biased way, the statistic is unreliable, so asking about sample size and selection weakens it.','If very few dentists were surveyed or they were selected in a biased way, the statistic is unreliable, so asking about sample size and selection weakens it.','Statistical claims depend heavily on how the sample was gathered. A small or non-random sample can produce misleading results that do not represent the broader population. Questioning sample size and selection method exposes potential bias in the claim.','Statistical claims depend heavily on how the sample was gathered. A small or non-random sample can produce misleading results that do not represent the broader population. Questioning sample size and selection method exposes potential bias in the claim.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reasoning-a-1','exam','exam:reasoning','exam-reasoning-a-1','advanced','mcq','Argument: ''Since the new manager arrived, sales have doubled, so the manager caused the increase.'' Which is the strongest objection to this reasoning?','Argument: ''Since the new manager arrived, sales have doubled, so the manager caused the increase.'' Which is the strongest objection to this reasoning?',ARRAY['The manager is well liked','Other factors, like a new product launch, may have driven sales','Sales figures are hard to read','The manager arrived on a Monday']::text[],ARRAY['The manager is well liked','Other factors, like a new product launch, may have driven sales','Sales figures are hard to read','The manager arrived on a Monday']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Attributing the rise solely to the manager ignores other possible causes such as a product launch, which is the strongest objection.','Attributing the rise solely to the manager ignores other possible causes such as a product launch, which is the strongest objection.','A causal argument is weakened when alternative explanations for the outcome are overlooked. The fact that one event preceded another does not prove it caused it, a fallacy called post hoc reasoning. Pointing to plausible competing causes undermines the claimed cause-and-effect link.','A causal argument is weakened when alternative explanations for the outcome are overlooked. The fact that one event preceded another does not prove it caused it, a fallacy called post hoc reasoning. Pointing to plausible competing causes undermines the claimed cause-and-effect link.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-exam-reasoning-a-2','exam','exam:reasoning','exam-reasoning-a-2','advanced','mcq','A politician says, ''My opponent wants to cut the military budget, so he clearly wants the country to be defenseless.'' Which logical flaw does this argument commit?','A politician says, ''My opponent wants to cut the military budget, so he clearly wants the country to be defenseless.'' Which logical flaw does this argument commit?',ARRAY['Circular reasoning','Straw man (misrepresenting the opponent''s position)','Appeal to authority','Valid deduction']::text[],ARRAY['Circular reasoning','Straw man (misrepresenting the opponent''s position)','Appeal to authority','Valid deduction']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Reducing a budget is not the same as wanting defenselessness, so the politician distorts the opponent''s view, which is a straw man.','Reducing a budget is not the same as wanting defenselessness, so the politician distorts the opponent''s view, which is a straw man.','A straw man fallacy misrepresents or exaggerates an opponent''s position to make it easier to attack. Refuting the distorted version does not address the actual argument. Recognizing the gap between the real claim and the caricature reveals the flaw.','A straw man fallacy misrepresents or exaggerates an opponent''s position to make it easier to attack. Refuting the distorted version does not address the actual argument. Recognizing the gap between the real claim and the caricature reveals the flaw.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-vocab-1','spanish','spanish:vocab','spanish-vocab-1','beginner','mcq','How do you say "good morning" in Spanish?','How do you say "good morning" in Spanish?',ARRAY['Buenos días','Buenas noches','Buenas tardes','Buen provecho']::text[],ARRAY['Buenos días','Buenas noches','Buenas tardes','Buen provecho']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Buenos días" is the standard greeting used in the morning, literally meaning "good days."','"Buenos días" is the standard greeting used in the morning, literally meaning "good days."','Spanish has three time-of-day greetings: "buenos días" (morning), "buenas tardes" (afternoon), and "buenas noches" (evening/night). Notice that "días" is masculine plural while "tardes" and "noches" are feminine, which is why the adjective changes between "buenos" and "buenas." These phrases are used both as greetings and as farewells.','Spanish has three time-of-day greetings: "buenos días" (morning), "buenas tardes" (afternoon), and "buenas noches" (evening/night). Notice that "días" is masculine plural while "tardes" and "noches" are feminine, which is why the adjective changes between "buenos" and "buenas." These phrases are used both as greetings and as farewells.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-vocab-2','spanish','spanish:vocab','spanish-vocab-2','intermediate','mcq','Which Spanish word means "to be hungry" when used in the phrase "tener ___"?','Which Spanish word means "to be hungry" when used in the phrase "tener ___"?',ARRAY['hambre','sed','sueño','frío']::text[],ARRAY['hambre','sed','sueño','frío']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Tener hambre" literally means "to have hunger," which is how Spanish expresses being hungry.','"Tener hambre" literally means "to have hunger," which is how Spanish expresses being hungry.','Spanish often uses the verb "tener" (to have) plus a noun where English uses "to be" plus an adjective. Common examples include "tener hambre" (hungry), "tener sed" (thirsty), "tener sueño" (sleepy), and "tener frío" (cold). Because these use a noun, you intensify them with "mucho/mucha" (a lot) rather than "muy" (very): "tengo mucha hambre."','Spanish often uses the verb "tener" (to have) plus a noun where English uses "to be" plus an adjective. Common examples include "tener hambre" (hungry), "tener sed" (thirsty), "tener sueño" (sleepy), and "tener frío" (cold). Because these use a noun, you intensify them with "mucho/mucha" (a lot) rather than "muy" (very): "tengo mucha hambre."',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-vocab-3','spanish','spanish:vocab','spanish-vocab-3','advanced','mcq','What does the idiom "estar en las nubes" mean?','What does the idiom "estar en las nubes" mean?',ARRAY['To be daydreaming','To be very tall','To be on a plane','To be in a bad mood']::text[],ARRAY['To be daydreaming','To be very tall','To be on a plane','To be in a bad mood']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Estar en las nubes" literally means "to be in the clouds" and idiomatically means to be distracted or daydreaming.','"Estar en las nubes" literally means "to be in the clouds" and idiomatically means to be distracted or daydreaming.','Idioms rarely translate word-for-word, so they must be learned as fixed expressions. "Estar en las nubes" matches the English image of having one''s "head in the clouds." Many Spanish idioms use "estar" plus a vivid image, such as "estar como una cabra" (to be crazy) or "estar hecho polvo" (to be exhausted).','Idioms rarely translate word-for-word, so they must be learned as fixed expressions. "Estar en las nubes" matches the English image of having one''s "head in the clouds." Many Spanish idioms use "estar" plus a vivid image, such as "estar como una cabra" (to be crazy) or "estar hecho polvo" (to be exhausted).',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-grammar-1','spanish','spanish:grammar','spanish-grammar-1','beginner','mcq','Which is the correct way to say "the book" in Spanish?','Which is the correct way to say "the book" in Spanish?',ARRAY['el libro','la libro','los libro','la libra']::text[],ARRAY['el libro','la libro','los libro','la libra']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Libro" is a masculine singular noun, so it takes the masculine singular article "el."','"Libro" is a masculine singular noun, so it takes the masculine singular article "el."','Every Spanish noun has a gender, masculine or feminine, and the article must match it. "El" is the masculine singular "the" and "la" is the feminine singular "the." Most nouns ending in -o are masculine and most ending in -a are feminine, though there are exceptions you simply memorize.','Every Spanish noun has a gender, masculine or feminine, and the article must match it. "El" is the masculine singular "the" and "la" is the feminine singular "the." Most nouns ending in -o are masculine and most ending in -a are feminine, though there are exceptions you simply memorize.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-grammar-2','spanish','spanish:grammar','spanish-grammar-2','intermediate','mcq','How do you correctly say "the red houses" (plural) in Spanish?','How do you correctly say "the red houses" (plural) in Spanish?',ARRAY['las casas rojas','los casas rojos','las casa roja','la casas roja']::text[],ARRAY['las casas rojas','los casas rojos','las casa roja','la casas roja']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Casa" is feminine and plural here, so the article, noun, and adjective all take feminine plural forms: "las casas rojas."','"Casa" is feminine and plural here, so the article, noun, and adjective all take feminine plural forms: "las casas rojas."','In Spanish, adjectives and articles must agree with the noun in both gender and number. When a noun is feminine plural, its article ("las") and any descriptive adjective ("rojas") also become feminine plural. Adjectives ending in -o/-a change their ending to match, while many ending in -e or a consonant only change for number.','In Spanish, adjectives and articles must agree with the noun in both gender and number. When a noun is feminine plural, its article ("las") and any descriptive adjective ("rojas") also become feminine plural. Adjectives ending in -o/-a change their ending to match, while many ending in -e or a consonant only change for number.',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-grammar-3','spanish','spanish:grammar','spanish-grammar-3','advanced','mcq','Which noun is grammatically masculine despite ending in -a?','Which noun is grammatically masculine despite ending in -a?',ARRAY['el problema','la mesa','la silla','la ventana']::text[],ARRAY['el problema','la mesa','la silla','la ventana']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"El problema" is masculine because many words of Greek origin ending in -ma are masculine, despite the -a ending.','"El problema" is masculine because many words of Greek origin ending in -ma are masculine, despite the -a ending.','The rule "-a means feminine" has notable exceptions, especially nouns of Greek origin ending in -ma, such as "el problema," "el tema," "el sistema," and "el idioma." These take masculine articles and adjectives: "un problema serio." Recognizing these patterns helps you avoid a common learner mistake.','The rule "-a means feminine" has notable exceptions, especially nouns of Greek origin ending in -ma, such as "el problema," "el tema," "el sistema," and "el idioma." These take masculine articles and adjectives: "un problema serio." Recognizing these patterns helps you avoid a common learner mistake.',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-verbs-1','spanish','spanish:verbs','spanish-verbs-1','beginner','mcq','How do you say "I speak" in Spanish (from the verb "hablar")?','How do you say "I speak" in Spanish (from the verb "hablar")?',ARRAY['hablo','hablas','habla','hablan']::text[],ARRAY['hablo','hablas','habla','hablan']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'For -ar verbs, the "yo" (I) form replaces -ar with -o, giving "hablo."','For -ar verbs, the "yo" (I) form replaces -ar with -o, giving "hablo."','Spanish verbs change their endings to show who is doing the action, so the subject pronoun is often dropped. For regular -ar verbs in the present tense, the endings are -o, -as, -a, -amos, -áis, -an. So "hablar" becomes "hablo" (I speak), "hablas" (you speak), and "habla" (he/she speaks).','Spanish verbs change their endings to show who is doing the action, so the subject pronoun is often dropped. For regular -ar verbs in the present tense, the endings are -o, -as, -a, -amos, -áis, -an. So "hablar" becomes "hablo" (I speak), "hablas" (you speak), and "habla" (he/she speaks).',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-verbs-2','spanish','spanish:verbs','spanish-verbs-2','intermediate','mcq','Which sentence correctly uses the preterite to say "I ate paella yesterday"?','Which sentence correctly uses the preterite to say "I ate paella yesterday"?',ARRAY['Ayer comí paella','Ayer como paella','Ayer comeré paella','Ayer comía paella']::text[],ARRAY['Ayer comí paella','Ayer como paella','Ayer comeré paella','Ayer comía paella']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Comí" is the first-person preterite of "comer," used for a completed action at a specific past time like "ayer" (yesterday).','"Comí" is the first-person preterite of "comer," used for a completed action at a specific past time like "ayer" (yesterday).','The preterite tense describes completed actions in the past, especially at a defined moment. For regular -er verbs like "comer," the "yo" preterite ending is -í, giving "comí." This contrasts with the imperfect ("comía"), which describes ongoing or habitual past actions rather than a single finished event.','The preterite tense describes completed actions in the past, especially at a defined moment. For regular -er verbs like "comer," the "yo" preterite ending is -í, giving "comí." This contrasts with the imperfect ("comía"), which describes ongoing or habitual past actions rather than a single finished event.',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-verbs-3','spanish','spanish:verbs','spanish-verbs-3','advanced','mcq','Which form correctly completes "Espero que tú ___ (venir) a la fiesta" (I hope that you come to the party)?','Which form correctly completes "Espero que tú ___ (venir) a la fiesta" (I hope that you come to the party)?',ARRAY['vengas','vienes','vendrás','viniste']::text[],ARRAY['vengas','vienes','vendrás','viniste']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The phrase "espero que" expresses hope and triggers the subjunctive, so "venir" becomes the present subjunctive "vengas."','The phrase "espero que" expresses hope and triggers the subjunctive, so "venir" becomes the present subjunctive "vengas."','The subjunctive mood expresses wishes, doubts, emotions, and uncertainty rather than facts. Expressions like "espero que" (I hope that) or "quiero que" (I want that) require the verb in the dependent clause to be subjunctive. "Venir" is irregular, taking the stem "veng-" so the present subjunctive "tú" form is "vengas."','The subjunctive mood expresses wishes, doubts, emotions, and uncertainty rather than facts. Expressions like "espero que" (I hope that) or "quiero que" (I want that) require the verb in the dependent clause to be subjunctive. "Venir" is irregular, taking the stem "veng-" so the present subjunctive "tú" form is "vengas."',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-conversation-1','spanish','spanish:conversation','spanish-conversation-1','beginner','mcq','Someone says "¿Cómo estás?" How do you reply "I''m fine, thank you"?','Someone says "¿Cómo estás?" How do you reply "I''m fine, thank you"?',ARRAY['Bien, gracias','Me llamo Ana','Hasta luego','De nada']::text[],ARRAY['Bien, gracias','Me llamo Ana','Hasta luego','De nada']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Bien, gracias" means "fine, thanks" and is the natural response to being asked how you are.','"Bien, gracias" means "fine, thanks" and is the natural response to being asked how you are.','"¿Cómo estás?" is the informal way to ask "How are you?" A common reply is "Bien, gracias" (fine, thank you), often followed by "¿y tú?" (and you?) to return the question. The other options mean "My name is Ana," "See you later," and "You''re welcome," which answer different prompts.','"¿Cómo estás?" is the informal way to ask "How are you?" A common reply is "Bien, gracias" (fine, thank you), often followed by "¿y tú?" (and you?) to return the question. The other options mean "My name is Ana," "See you later," and "You''re welcome," which answer different prompts.',10,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-conversation-2','spanish','spanish:conversation','spanish-conversation-2','intermediate','mcq','At a restaurant, how would you politely ask for the bill?','At a restaurant, how would you politely ask for the bill?',ARRAY['La cuenta, por favor','El menú, por favor','Un café, por favor','La carta, por favor']::text[],ARRAY['La cuenta, por favor','El menú, por favor','Un café, por favor','La carta, por favor']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"La cuenta" means "the bill," so "la cuenta, por favor" is how you politely request it.','"La cuenta" means "the bill," so "la cuenta, por favor" is how you politely request it.','In a Spanish restaurant, "la cuenta" is the bill you ask for at the end of a meal, while "la carta" or "el menú" is the menu you read at the start. Adding "por favor" (please) keeps the request polite. You can also signal a waiter and say "¿Me trae la cuenta, por favor?" (Could you bring me the bill, please?).','In a Spanish restaurant, "la cuenta" is the bill you ask for at the end of a meal, while "la carta" or "el menú" is the menu you read at the start. Adding "por favor" (please) keeps the request polite. You can also signal a waiter and say "¿Me trae la cuenta, por favor?" (Could you bring me the bill, please?).',15,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-spanish-conversation-3','spanish','spanish:conversation','spanish-conversation-3','advanced','truefalse','In most of Spain, you would use "vosotros" to address a group of friends informally, while much of Latin America uses "ustedes" instead. True or False?','In most of Spain, you would use "vosotros" to address a group of friends informally, while much of Latin America uses "ustedes" instead. True or False?',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Spain commonly uses the informal plural "vosotros" for groups of friends, whereas Latin America generally uses "ustedes" for all plural "you."','Spain commonly uses the informal plural "vosotros" for groups of friends, whereas Latin America generally uses "ustedes" for all plural "you."','Spanish has multiple ways to say "you," and usage varies by region. Spain distinguishes informal plural "vosotros" from formal plural "ustedes," each with its own verb forms. Most of Latin America has dropped "vosotros" entirely, using "ustedes" for any group regardless of formality, so learners traveling between regions should expect this difference.','Spanish has multiple ways to say "you," and usage varies by region. Spain distinguishes informal plural "vosotros" from formal plural "ustedes," each with its own verb forms. Most of Latin America has dropped "vosotros" entirely, using "ustedes" for any group regardless of formality, so learners traveling between regions should expect this difference.',25,'approved','curated-taste');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-vocab-b-1','spanish','spanish:vocab','spanish-vocab-b-1','beginner','mcq','How do you say "good morning" in Spanish?','How do you say "good morning" in Spanish?',ARRAY['Buenos días','Buenas noches','Buenas tardes','Hasta luego']::text[],ARRAY['Buenos días','Buenas noches','Buenas tardes','Hasta luego']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Buenos días" is the standard greeting used in the morning.','"Buenos días" is the standard greeting used in the morning.','Spanish greetings change with the time of day. "Buenos días" is used in the morning, "buenas tardes" in the afternoon, and "buenas noches" in the evening or at night. "Hasta luego" means "see you later" and is a farewell, not a greeting.','Spanish greetings change with the time of day. "Buenos días" is used in the morning, "buenas tardes" in the afternoon, and "buenas noches" in the evening or at night. "Hasta luego" means "see you later" and is a farewell, not a greeting.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-vocab-b-2','spanish','spanish:vocab','spanish-vocab-b-2','beginner','mcq','What does the Spanish word "gracias" mean in English?','What does the Spanish word "gracias" mean in English?',ARRAY['Thank you','Please','Sorry','Goodbye']::text[],ARRAY['Thank you','Please','Sorry','Goodbye']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Gracias" is the common Spanish word for "thank you."','"Gracias" is the common Spanish word for "thank you."','"Gracias" means "thank you." To say "please" you use "por favor," and "you''re welcome" is "de nada." These three polite phrases are among the first any learner should memorize.','"Gracias" means "thank you." To say "please" you use "por favor," and "you''re welcome" is "de nada." These three polite phrases are among the first any learner should memorize.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-vocab-i-1','spanish','spanish:vocab','spanish-vocab-i-1','intermediate','mcq','Which Spanish word means "to be hungry" when used in the phrase "tener ___"?','Which Spanish word means "to be hungry" when used in the phrase "tener ___"?',ARRAY['hambre','sed','sueño','frío']::text[],ARRAY['hambre','sed','sueño','frío']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Tener hambre" literally means "to have hunger," the standard way to say you are hungry.','"Tener hambre" literally means "to have hunger," the standard way to say you are hungry.','Spanish expresses many physical states with "tener" (to have) plus a noun. "Tener hambre" is to be hungry, "tener sed" to be thirsty, "tener sueño" to be sleepy, and "tener frío" to be cold. English uses "to be" for these, so this is a common point of confusion.','Spanish expresses many physical states with "tener" (to have) plus a noun. "Tener hambre" is to be hungry, "tener sed" to be thirsty, "tener sueño" to be sleepy, and "tener frío" to be cold. English uses "to be" for these, so this is a common point of confusion.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-vocab-i-2','spanish','spanish:vocab','spanish-vocab-i-2','intermediate','mcq','What is the most natural Spanish phrase for "How much does it cost?"','What is the most natural Spanish phrase for "How much does it cost?"',ARRAY['¿Cuánto cuesta?','¿Cómo está?','¿Cuándo es?','¿Qué tal?']::text[],ARRAY['¿Cuánto cuesta?','¿Cómo está?','¿Cuándo es?','¿Qué tal?']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"¿Cuánto cuesta?" asks the price of a single item.','"¿Cuánto cuesta?" asks the price of a single item.','"¿Cuánto cuesta?" means "How much does it cost?" for one thing, while "¿Cuánto cuestan?" is used for several items. Note the inverted question mark (¿) that opens every Spanish question. "¿Qué tal?" simply means "How''s it going?"','"¿Cuánto cuesta?" means "How much does it cost?" for one thing, while "¿Cuánto cuestan?" is used for several items. Note the inverted question mark (¿) that opens every Spanish question. "¿Qué tal?" simply means "How''s it going?"',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-vocab-a-1','spanish','spanish:vocab','spanish-vocab-a-1','advanced','mcq','The Spanish idiom "estar en las nubes" is best translated as which English expression?','The Spanish idiom "estar en las nubes" is best translated as which English expression?',ARRAY['To have one''s head in the clouds','To be on cloud nine','To be under the weather','To rain on someone''s parade']::text[],ARRAY['To have one''s head in the clouds','To be on cloud nine','To be under the weather','To rain on someone''s parade']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Estar en las nubes" describes someone distracted or daydreaming, matching "to have one''s head in the clouds."','"Estar en las nubes" describes someone distracted or daydreaming, matching "to have one''s head in the clouds."','Idioms rarely translate word for word. "Estar en las nubes" literally means "to be in the clouds" and describes inattentiveness, not happiness. The English "on cloud nine" means joy, which in Spanish would be "estar en el séptimo cielo" (in the seventh heaven).','Idioms rarely translate word for word. "Estar en las nubes" literally means "to be in the clouds" and describes inattentiveness, not happiness. The English "on cloud nine" means joy, which in Spanish would be "estar en el séptimo cielo" (in the seventh heaven).',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-vocab-a-2','spanish','spanish:vocab','spanish-vocab-a-2','advanced','truefalse','True or False: In Spanish, "embarazada" is a false friend and actually means "pregnant," not "embarrassed."','True or False: In Spanish, "embarazada" is a false friend and actually means "pregnant," not "embarrassed."',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Embarazada" means "pregnant"; to say "embarrassed" you use "avergonzado" or "avergonzada."','"Embarazada" means "pregnant"; to say "embarrassed" you use "avergonzado" or "avergonzada."','False friends ("falsos amigos") are words that look similar across languages but differ in meaning. "Embarazada" means pregnant, not embarrassed. Other examples include "éxito" (success, not exit) and "actualmente" (currently, not actually).','False friends ("falsos amigos") are words that look similar across languages but differ in meaning. "Embarazada" means pregnant, not embarrassed. Other examples include "éxito" (success, not exit) and "actualmente" (currently, not actually).',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-grammar-b-1','spanish','spanish:grammar','spanish-grammar-b-1','beginner','mcq','Which definite article correctly completes "___ casa" (the house), given that "casa" is feminine?','Which definite article correctly completes "___ casa" (the house), given that "casa" is feminine?',ARRAY['la','el','los','las']::text[],ARRAY['la','el','los','las']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Casa" is a singular feminine noun, so it takes the article "la."','"Casa" is a singular feminine noun, so it takes the article "la."','Spanish nouns have grammatical gender. Singular feminine nouns take "la," singular masculine nouns take "el," and the plural forms are "las" and "los." Many feminine nouns end in -a, like "casa" (house).','Spanish nouns have grammatical gender. Singular feminine nouns take "la," singular masculine nouns take "el," and the plural forms are "las" and "los." Many feminine nouns end in -a, like "casa" (house).',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-grammar-b-2','spanish','spanish:grammar','spanish-grammar-b-2','beginner','mcq','What is the correct plural of the Spanish noun "libro" (book)?','What is the correct plural of the Spanish noun "libro" (book)?',ARRAY['libros','libroes','libres','librs']::text[],ARRAY['libros','libroes','libres','librs']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Nouns ending in a vowel form the plural by adding -s, giving "libros."','Nouns ending in a vowel form the plural by adding -s, giving "libros."','To make most Spanish nouns plural, add -s if the word ends in a vowel (libro to libros) and -es if it ends in a consonant (papel to papeles). The article also becomes plural, so "el libro" becomes "los libros."','To make most Spanish nouns plural, add -s if the word ends in a vowel (libro to libros) and -es if it ends in a consonant (papel to papeles). The article also becomes plural, so "el libro" becomes "los libros."',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-grammar-i-1','spanish','spanish:grammar','spanish-grammar-i-1','intermediate','mcq','Choose the correct adjective agreement: "the red cars" in Spanish.','Choose the correct adjective agreement: "the red cars" in Spanish.',ARRAY['los coches rojos','los coches roja','las coches rojos','el coche rojos']::text[],ARRAY['los coches rojos','los coches roja','las coches rojos','el coche rojos']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Coches" is masculine plural, so the adjective must be masculine plural: "rojos."','"Coches" is masculine plural, so the adjective must be masculine plural: "rojos."','In Spanish, adjectives agree with their noun in both gender and number. Because "coches" is masculine and plural, the adjective "rojo" becomes "rojos." Adjectives usually follow the noun they describe, unlike in English.','In Spanish, adjectives agree with their noun in both gender and number. Because "coches" is masculine and plural, the adjective "rojo" becomes "rojos." Adjectives usually follow the noun they describe, unlike in English.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-grammar-i-2','spanish','spanish:grammar','spanish-grammar-i-2','intermediate','mcq','Which word correctly completes "Este libro es ___" to mean "This book is mine"?','Which word correctly completes "Este libro es ___" to mean "This book is mine"?',ARRAY['mío','mi','me','yo']::text[],ARRAY['mío','mi','me','yo']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'After the verb, the stressed possessive "mío" is used to mean "mine."','After the verb, the stressed possessive "mío" is used to mean "mine."','Spanish has two kinds of possessives. The short forms (mi, tu, su) go before a noun: "mi libro" (my book). The long, stressed forms (mío, tuyo, suyo) stand alone or follow the verb "ser": "el libro es mío" (the book is mine).','Spanish has two kinds of possessives. The short forms (mi, tu, su) go before a noun: "mi libro" (my book). The long, stressed forms (mío, tuyo, suyo) stand alone or follow the verb "ser": "el libro es mío" (the book is mine).',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-grammar-a-1','spanish','spanish:grammar','spanish-grammar-a-1','advanced','mcq','Which sentence correctly uses the "personal a" before a direct object that is a person?','Which sentence correctly uses the "personal a" before a direct object that is a person?',ARRAY['Veo a María','Veo María','Veo el María','Veo de María']::text[],ARRAY['Veo a María','Veo María','Veo el María','Veo de María']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'When the direct object is a specific person, Spanish requires the "personal a": "Veo a María."','When the direct object is a specific person, Spanish requires the "personal a": "Veo a María."','The "personal a" is placed before a direct object that refers to a specific person or pet. It has no English equivalent and is not translated. So "I see María" becomes "Veo a María," while "I see the house" stays "Veo la casa" with no "a."','The "personal a" is placed before a direct object that refers to a specific person or pet. It has no English equivalent and is not translated. So "I see María" becomes "Veo a María," while "I see the house" stays "Veo la casa" with no "a."',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-grammar-a-2','spanish','spanish:grammar','spanish-grammar-a-2','advanced','truefalse','True or False: The Spanish noun "el problema" is masculine even though it ends in -a.','True or False: The Spanish noun "el problema" is masculine even though it ends in -a.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"El problema" is masculine; many Greek-derived nouns ending in -ma are masculine.','"El problema" is masculine; many Greek-derived nouns ending in -ma are masculine.','While most -a nouns are feminine, a group of words of Greek origin ending in -ma are masculine, such as "el problema," "el tema," "el idioma," and "el sistema." These must simply be memorized as exceptions to the usual gender rule.','While most -a nouns are feminine, a group of words of Greek origin ending in -ma are masculine, such as "el problema," "el tema," "el idioma," and "el sistema." These must simply be memorized as exceptions to the usual gender rule.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-verbs-b-1','spanish','spanish:verbs','spanish-verbs-b-1','beginner','mcq','What is the correct present-tense form of "hablar" (to speak) for "yo" (I)?','What is the correct present-tense form of "hablar" (to speak) for "yo" (I)?',ARRAY['hablo','hablas','habla','hablan']::text[],ARRAY['hablo','hablas','habla','hablan']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'For -ar verbs, the "yo" form ends in -o, giving "hablo."','For -ar verbs, the "yo" form ends in -o, giving "hablo."','Regular -ar verbs in the present tense drop -ar and add endings: -o (yo), -as (tú), -a (él/ella), -amos (nosotros), -an (ellos). So "yo hablo" means "I speak." This pattern applies to most -ar verbs.','Regular -ar verbs in the present tense drop -ar and add endings: -o (yo), -as (tú), -a (él/ella), -amos (nosotros), -an (ellos). So "yo hablo" means "I speak." This pattern applies to most -ar verbs.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-verbs-b-2','spanish','spanish:verbs','spanish-verbs-b-2','beginner','mcq','Which form of "ser" (to be) correctly completes "Yo ___ estudiante" (I am a student)?','Which form of "ser" (to be) correctly completes "Yo ___ estudiante" (I am a student)?',ARRAY['soy','eres','es','somos']::text[],ARRAY['soy','eres','es','somos']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The first-person form of "ser" is "soy," so "Yo soy estudiante."','The first-person form of "ser" is "soy," so "Yo soy estudiante."','"Ser" is an irregular verb meaning "to be." Its present forms are soy, eres, es, somos, sois, son. "Ser" is used for permanent traits and identity, such as professions: "Yo soy estudiante" (I am a student).','"Ser" is an irregular verb meaning "to be." Its present forms are soy, eres, es, somos, sois, son. "Ser" is used for permanent traits and identity, such as professions: "Yo soy estudiante" (I am a student).',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-verbs-i-1','spanish','spanish:verbs','spanish-verbs-i-1','intermediate','mcq','Which sentence correctly uses "estar" rather than "ser" to describe a temporary state?','Which sentence correctly uses "estar" rather than "ser" to describe a temporary state?',ARRAY['Estoy cansado','Soy cansado','Estoy médico','Soy en casa']::text[],ARRAY['Estoy cansado','Soy cansado','Estoy médico','Soy en casa']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Temporary conditions like tiredness use "estar": "Estoy cansado" (I am tired).','Temporary conditions like tiredness use "estar": "Estoy cansado" (I am tired).','Spanish has two verbs for "to be." "Ser" describes permanent qualities and identity, while "estar" describes temporary states, locations, and feelings. Being tired is temporary, so it requires "estar": "Estoy cansado."','Spanish has two verbs for "to be." "Ser" describes permanent qualities and identity, while "estar" describes temporary states, locations, and feelings. Being tired is temporary, so it requires "estar": "Estoy cansado."',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-verbs-i-2','spanish','spanish:verbs','spanish-verbs-i-2','intermediate','mcq','What is the correct preterite (simple past) form for "comer" (to eat) with "yo"?','What is the correct preterite (simple past) form for "comer" (to eat) with "yo"?',ARRAY['comí','como','comía','comeré']::text[],ARRAY['comí','como','comía','comeré']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The preterite "yo" form of -er verbs ends in -í, giving "comí" (I ate).','The preterite "yo" form of -er verbs ends in -í, giving "comí" (I ate).','The preterite tense describes completed past actions. For regular -er and -ir verbs, the "yo" ending is -í: "comí" (I ate). Be careful not to confuse it with the imperfect "comía" (I was eating / used to eat), which describes ongoing past actions.','The preterite tense describes completed past actions. For regular -er and -ir verbs, the "yo" ending is -í: "comí" (I ate). Be careful not to confuse it with the imperfect "comía" (I was eating / used to eat), which describes ongoing past actions.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-verbs-a-1','spanish','spanish:verbs','spanish-verbs-a-1','advanced','mcq','Which sentence correctly uses the present subjunctive after "espero que" (I hope that)?','Which sentence correctly uses the present subjunctive after "espero que" (I hope that)?',ARRAY['Espero que vengas','Espero que vienes','Espero que vendrás','Espero que viniste']::text[],ARRAY['Espero que vengas','Espero que vienes','Espero que vendrás','Espero que viniste']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Expressions of hope trigger the subjunctive, so "venir" becomes "vengas."','Expressions of hope trigger the subjunctive, so "venir" becomes "vengas."','The subjunctive mood expresses wishes, doubts, and emotions. Verbs of hope, desire, or emotion followed by "que" require the subjunctive in the second clause. "Espero que vengas" means "I hope you come," using the subjunctive form "vengas" rather than the indicative "vienes."','The subjunctive mood expresses wishes, doubts, and emotions. Verbs of hope, desire, or emotion followed by "que" require the subjunctive in the second clause. "Espero que vengas" means "I hope you come," using the subjunctive form "vengas" rather than the indicative "vienes."',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-verbs-a-2','spanish','spanish:verbs','spanish-verbs-a-2','advanced','truefalse','True or False: In Spanish, the present perfect "he comido" is formed with the auxiliary verb "haber" plus a past participle.','True or False: In Spanish, the present perfect "he comido" is formed with the auxiliary verb "haber" plus a past participle.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"He comido" combines "haber" (he) with the past participle "comido," forming the present perfect.','"He comido" combines "haber" (he) with the past participle "comido," forming the present perfect.','The Spanish present perfect uses "haber" as the auxiliary plus a past participle, such as "he comido" (I have eaten). "Haber" conjugates as he, has, ha, hemos, habéis, han. Unlike English, only "haber" serves this role, never "tener."','The Spanish present perfect uses "haber" as the auxiliary plus a past participle, such as "he comido" (I have eaten). "Haber" conjugates as he, has, ha, hemos, habéis, han. Unlike English, only "haber" serves this role, never "tener."',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-conversation-b-1','spanish','spanish:conversation','spanish-conversation-b-1','beginner','mcq','Someone asks "¿Cómo te llamas?" How do you say "My name is Ana"?','Someone asks "¿Cómo te llamas?" How do you say "My name is Ana"?',ARRAY['Me llamo Ana','Te llamas Ana','Se llama Ana','Llamo Ana']::text[],ARRAY['Me llamo Ana','Te llamas Ana','Se llama Ana','Llamo Ana']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Me llamo Ana" literally means "I call myself Ana," the standard way to give your name.','"Me llamo Ana" literally means "I call myself Ana," the standard way to give your name.','To ask someone''s name, Spanish uses "¿Cómo te llamas?" (literally "What do you call yourself?"). You answer with "Me llamo" plus your name. This uses the reflexive verb "llamarse," where "me" refers back to yourself.','To ask someone''s name, Spanish uses "¿Cómo te llamas?" (literally "What do you call yourself?"). You answer with "Me llamo" plus your name. This uses the reflexive verb "llamarse," where "me" refers back to yourself.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-conversation-b-2','spanish','spanish:conversation','spanish-conversation-b-2','beginner','mcq','How do you politely ask "Where is the bathroom?" in Spanish?','How do you politely ask "Where is the bathroom?" in Spanish?',ARRAY['¿Dónde está el baño?','¿Qué es el baño?','¿Cómo está el baño?','¿Cuándo es el baño?']::text[],ARRAY['¿Dónde está el baño?','¿Qué es el baño?','¿Cómo está el baño?','¿Cuándo es el baño?']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"¿Dónde está el baño?" asks for the location of the bathroom using "dónde" (where).','"¿Dónde está el baño?" asks for the location of the bathroom using "dónde" (where).','The question word "dónde" means "where," and "está" (from "estar") is used for locations. So "¿Dónde está...?" means "Where is...?" This is one of the most useful travel phrases for finding any place.','The question word "dónde" means "where," and "está" (from "estar") is used for locations. So "¿Dónde está...?" means "Where is...?" This is one of the most useful travel phrases for finding any place.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-conversation-i-1','spanish','spanish:conversation','spanish-conversation-i-1','intermediate','mcq','At a restaurant, which phrase best means "I would like to order, please"?','At a restaurant, which phrase best means "I would like to order, please"?',ARRAY['Quisiera pedir, por favor','Quiero comer ahora','Tengo el menú','Voy a la cocina']::text[],ARRAY['Quisiera pedir, por favor','Quiero comer ahora','Tengo el menú','Voy a la cocina']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Quisiera" is a polite conditional form of "querer," and "pedir" means "to order."','"Quisiera" is a polite conditional form of "querer," and "pedir" means "to order."','"Quisiera" is the polite, softened way to say "I would like," more courteous than the direct "quiero" (I want). Combined with "pedir" (to order food), it is the natural phrase to call a waiter. Politeness markers like this matter in service settings.','"Quisiera" is the polite, softened way to say "I would like," more courteous than the direct "quiero" (I want). Combined with "pedir" (to order food), it is the natural phrase to call a waiter. Politeness markers like this matter in service settings.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-conversation-i-2','spanish','spanish:conversation','spanish-conversation-i-2','intermediate','mcq','A friend says "¡Muchas gracias!" Which is the most natural reply?','A friend says "¡Muchas gracias!" Which is the most natural reply?',ARRAY['De nada','Por favor','Con permiso','Lo siento']::text[],ARRAY['De nada','Por favor','Con permiso','Lo siento']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"De nada" means "you''re welcome," the standard response to thanks.','"De nada" means "you''re welcome," the standard response to thanks.','When someone thanks you, the customary reply is "de nada" (literally "of nothing"), equivalent to "you''re welcome." "Con permiso" means "excuse me" when passing by, and "lo siento" means "I''m sorry," so neither fits here.','When someone thanks you, the customary reply is "de nada" (literally "of nothing"), equivalent to "you''re welcome." "Con permiso" means "excuse me" when passing by, and "lo siento" means "I''m sorry," so neither fits here.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-conversation-a-1','spanish','spanish:conversation','spanish-conversation-a-1','advanced','mcq','In most of Spain, which pronoun and verb form would you use to address a group of friends informally as "you all"?','In most of Spain, which pronoun and verb form would you use to address a group of friends informally as "you all"?',ARRAY['vosotros habláis','ustedes hablan','tú hablas','nosotros hablamos']::text[],ARRAY['vosotros habláis','ustedes hablan','tú hablas','nosotros hablamos']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'In Spain, the informal plural "you all" is "vosotros," with verbs ending in -áis like "habláis."','In Spain, the informal plural "you all" is "vosotros," with verbs ending in -áis like "habláis."','Spain distinguishes informal plural "vosotros" from formal plural "ustedes," while most of Latin America uses "ustedes" for all plural "you." The "vosotros" form has its own endings, such as -áis for -ar verbs, giving "vosotros habláis."','Spain distinguishes informal plural "vosotros" from formal plural "ustedes," while most of Latin America uses "ustedes" for all plural "you." The "vosotros" form has its own endings, such as -áis for -ar verbs, giving "vosotros habláis."',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-spanish-conversation-a-2','spanish','spanish:conversation','spanish-conversation-a-2','advanced','truefalse','True or False: Using "usted" instead of "tú" shows greater formality or respect when speaking to someone in Spanish.','True or False: Using "usted" instead of "tú" shows greater formality or respect when speaking to someone in Spanish.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'"Usted" is the formal "you," used to show respect or social distance, whereas "tú" is informal.','"Usted" is the formal "you," used to show respect or social distance, whereas "tú" is informal.','Spanish marks formality through pronoun choice. "Tú" is informal, used with friends, family, and peers, while "usted" is formal, used with elders, strangers, or in professional settings. "Usted" takes third-person verb forms, as in "¿Cómo está usted?"','Spanish marks formality through pronoun choice. "Tú" is informal, used with friends, family, and peers, while "usted" is formal, used with elders, strangers, or in professional settings. "Usted" takes third-person verb forms, as in "¿Cómo está usted?"',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-python-syntax-1','python','python:syntax','python-syntax-1','beginner','mcq','Which symbol assigns a value to a variable in Python?
x ? 5','Which symbol assigns a value to a variable in Python?
