INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-python-syntax-2','python','python:syntax','python-syntax-2','intermediate','mcq','What is the data type of the value bound to y?
