INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bank-python-flow-3','python','python:flow','python-flow-3','advanced','mcq','What does this print?
