INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-python-syntax-b-2','python','python:syntax','python-syntax-b-2','beginner','mcq','Which symbol begins a single-line comment in Python?','Which symbol begins a single-line comment in Python?',ARRAY['#','//','--','/*']::text[],ARRAY['#','//','--','/*']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Python uses the hash symbol # to start a comment that runs to the end of the line.','Python uses the hash symbol # to start a comment that runs to the end of the line.','Comments are ignored by the interpreter and exist to explain code to humans. In Python a comment starts with # and continues to the end of that line. The // and /* styles belong to other languages such as C and Java.','Comments are ignored by the interpreter and exist to explain code to humans. In Python a comment starts with # and continues to the end of that line. The // and /* styles belong to other languages such as C and Java.',10,'approved','curated-bank');
